# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Initialize AWS clients outside handler for connection reuse
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')
rekognition_client = boto3.client('rekognition')

# Configuration from environment variables
RESULTS_BUCKET = os.environ.get('RESULTS_BUCKET', 'image-processing-results')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')
CONFIDENCE_THRESHOLD = float(os.environ.get('CONFIDENCE_THRESHOLD', '80.0'))
SUPPORTED_FORMATS = {'.jpg', '.jpeg', '.png', '.bmp', '.gif'}
MAX_IMAGE_SIZE_BYTES = 15 * 1024 * 1024  # 15 MB (Rekognition limit for S3)


def lambda_handler(event, context):
    """
    Main Lambda handler triggered by S3 put events.
    Processes uploaded images: analyzes with Rekognition, stores results,
    and sends SNS notifications.
    """
    logger.info("Received event: %s", json.dumps(event, default=str))

    processing_results = []

    for record in event.get('Records', []):
        try:
            result = process_record(record, context)
            processing_results.append(result)
        except Exception as e:
            error_result = handle_record_error(record, e)
            processing_results.append(error_result)

    successful = sum(1 for r in processing_results if r.get('status') == 'success')
    failed = sum(1 for r in processing_results if r.get('status') == 'error')

    summary = {
        'total_records': len(processing_results),
        'successful': successful,
        'failed': failed,
        'results': processing_results
    }

    logger.info("Processing complete: %d successful, %d failed", successful, failed)

    return {
        'statusCode': 200,
        'body': json.dumps(summary, default=str)
    }


def process_record(record, context):
    """Process a single S3 event record."""
    # Extract S3 info from the event record
    s3_event = record.get('s3', {})
    source_bucket = s3_event.get('bucket', {}).get('name', '')
    source_key = unquote_plus(s3_event.get('object', {}).get('key', ''))
    object_size = s3_event.get('object', {}).get('size', 0)

    logger.info("Processing image: s3://%s/%s (size: %d bytes)", source_bucket, source_key, object_size)

    # Validate the file
    validate_image(source_key, object_size)

    # Get image metadata from S3
    image_metadata = get_image_metadata(source_bucket, source_key)

    # Analyze image with Rekognition
    labels = detect_labels(source_bucket, source_key)
    moderation_labels = detect_moderation_labels(source_bucket, source_key)

    # Build processing result
    processing_result = build_result(
        source_bucket=source_bucket,
        source_key=source_key,
        object_size=object_size,
        image_metadata=image_metadata,
        labels=labels,
        moderation_labels=moderation_labels,
        context=context
    )

    # Write results to S3
    results_key = write_results_to_s3(source_key, processing_result)

    # Send SNS notification
    send_notification(source_key, processing_result)

    logger.info("Successfully processed: %s -> results at s3://%s/%s",
                source_key, RESULTS_BUCKET, results_key)

    return {
        'status': 'success',
        'source_key': source_key,
        'results_key': results_key,
        'label_count': len(labels),
        'moderation_flag': len(moderation_labels) > 0
    }


def validate_image(key, size):
    """Validate that the file is a supported image format and within size limits."""
    file_ext = os.path.splitext(key)[1].lower()

    if file_ext not in SUPPORTED_FORMATS:
        raise ValueError(
            f"Unsupported file format: '{file_ext}'. "
            f"Supported formats: {', '.join(sorted(SUPPORTED_FORMATS))}"
        )

    if size > MAX_IMAGE_SIZE_BYTES:
        raise ValueError(
            f"Image size {size} bytes exceeds maximum allowed "
            f"{MAX_IMAGE_SIZE_BYTES} bytes"
        )

    if size == 0:
        raise ValueError("Image file is empty (0 bytes)")


def get_image_metadata(bucket, key):
    """Retrieve object metadata from S3."""
    try:
        response = s3_client.head_object(Bucket=bucket, Key=key)
        return {
            'content_type': response.get('ContentType', 'unknown'),
            'content_length': response.get('ContentLength', 0),
            'last_modified': response.get('LastModified', ''),
            'etag': response.get('ETag', ''),
            'user_metadata': response.get('Metadata', {})
        }
    except s3_client.exceptions.ClientError as e:
        logger.warning("Could not retrieve metadata for s3://%s/%s: %s", bucket, key, str(e))
        return {}


def detect_labels(bucket, key):
    """Use Rekognition to detect labels in the image."""
    try:
        response = rekognition_client.detect_labels(
            Image={
                'S3Object': {
                    'Bucket': bucket,
                    'Name': key
                }
            },
            MaxLabels=20,
            MinConfidence=CONFIDENCE_THRESHOLD
        )

        labels = []
        for label in response.get('Labels', []):
            label_data = {
                'name': label.get('Name', ''),
                'confidence': round(label.get('Confidence', 0), 2),
                'categories': [cat.get('Name', '') for cat in label.get('Categories', [])],
                'parents': [p.get('Name', '') for p in label.get('Parents', [])],
                'instances': len(label.get('Instances', []))
            }
            labels.append(label_data)

        logger.info("Detected %d labels for %s", len(labels), key)
        return labels

    except rekognition_client.exceptions.InvalidImageFormatException:
        logger.error("Invalid image format for Rekognition: %s", key)
        raise ValueError(f"Image format not supported by Rekognition: {key}")
    except Exception as e:
        logger.error("Rekognition detect_labels failed for %s: %s", key, str(e))
        raise


def detect_moderation_labels(bucket, key):
    """Use Rekognition to detect moderation labels (unsafe content)."""
    try:
        response = rekognition_client.detect_moderation_labels(
            Image={
                'S3Object': {
                    'Bucket': bucket,
                    'Name': key
                }
            },
            MinConfidence=CONFIDENCE_THRESHOLD
        )

        moderation_labels = []
        for label in response.get('ModerationLabels', []):
            moderation_labels.append({
                'name': label.get('Name', ''),
                'confidence': round(label.get('Confidence', 0), 2),
                'parent_name': label.get('ParentName', '')
            })

        if moderation_labels:
            logger.warning("Moderation labels detected for %s: %s",
                           key, [ml['name'] for ml in moderation_labels])

        return moderation_labels

    except Exception as e:
        logger.error("Rekognition detect_moderation_labels failed for %s: %s", key, str(e))
        # Return empty list rather than failing the whole pipeline for moderation
        return []


def build_result(source_bucket, source_key, object_size, image_metadata,
                 labels, moderation_labels, context):
    """Build a structured result dictionary."""
    top_labels = [l['name'] for l in sorted(labels, key=lambda x: x['confidence'], reverse=True)[:5]]

    return {
        'processing_id': context.aws_request_id if context else 'local',
        'timestamp': datetime.utcnow().isoformat() + 'Z',
        'source': {
            'bucket': source_bucket,
            'key': source_key,
            'size_bytes': object_size,
            'metadata': image_metadata
        },
        'analysis': {
            'labels': labels,
            'label_count': len(labels),
            'top_labels': top_labels,
            'moderation_labels': moderation_labels,
            'is_flagged': len(moderation_labels) > 0,
            'confidence_threshold': CONFIDENCE_THRESHOLD
        },
        'lambda_context': {
            'function_name': getattr(context, 'function_name', 'local'),
            'function_version': getattr(context, 'function_version', 'N/A'),
            'request_id': getattr(context, 'aws_request_id', 'local'),
            'remaining_time_ms': context.get_remaining_time_in_millis() if context else 0
        }
    }


def write_results_to_s3(source_key, result):
    """Write processing results as JSON to the results S3 bucket."""
    # Create a results key based on the source key
    base_name = os.path.splitext(os.path.basename(source_key))[0]
    timestamp = datetime.utcnow().strftime('%Y%m%d_%H%M%S')
    results_key = f"results/{base_name}/{timestamp}_{result['processing_id']}.json"

    try:
        s3_client.put_object(
            Bucket=RESULTS_BUCKET,
            Key=results_key,
            Body=json.dumps(result, default=str, indent=2),
            ContentType='application/json',
            Metadata={
                'source-key': source_key,
                'processing-id': result['processing_id'],
                'label-count': str(result['analysis']['label_count']),
                'is-flagged': str(result['analysis']['is_flagged'])
            }
        )

        logger.info("Results written to s3://%s/%s", RESULTS_BUCKET, results_key)
        return results_key

    except Exception as e:
        logger.error("Failed to write results to S3: %s", str(e))
        raise


def send_notification(source_key, result):
    """Send an SNS notification about the processing result."""
    if not SNS_TOPIC_ARN:
        logger.info("SNS_TOPIC_ARN not configured, skipping notification")
        return

    is_flagged = result['analysis']['is_flagged']
    label_count = result['analysis']['label_count']
    top_labels = result['analysis']['top_labels']

    subject = f"{'⚠️ FLAGGED - ' if is_flagged else ''}Image Processed: {os.path.basename(source_key)}"
    # SNS subject max is 100 characters
    subject = subject[:100]

    message = {
        'default': json.dumps({
            'source_key': source_key,
            'processing_id': result['processing_id'],
            'timestamp': result['timestamp'],
            'label_count': label_count,
            'top_labels': top_labels,
            'is_flagged': is_flagged,
            'moderation_labels': [ml['name'] for ml in result['analysis']['moderation_labels']]
        }, default=str),
        'email': (
            f"Image Processing Result\n"
            f"{'=' * 40}\n\n"
            f"Image: {source_key}\n"
            f"Processing ID: {result['processing_id']}\n"
            f"Timestamp: {result['timestamp']}\n\n"
            f"Labels Detected: {label_count}\n"
            f"Top Labels: {', '.join(top_labels)}\n\n"
            f"Content Moderation: {'⚠️ FLAGGED' if is_flagged else '✅ Clean'}\n"
            f"{'Moderation Labels: ' + ', '.join([ml['name'] for ml in result['analysis']['moderation_labels']]) if is_flagged else ''}\n"
        )
    }

    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject,
            Message=json.dumps(message),
            MessageStructure='json',
            MessageAttributes={
                'is_flagged': {
                    'DataType': 'String',
                    'StringValue': str(is_flagged)
                },
                'label_count': {
                    'DataType': 'Number',
                    'StringValue': str(label_count)
                }
            }
        )
        logger.info("SNS notification sent for %s", source_key)

    except Exception as e:
        # Don't fail the whole processing if notification fails
        logger.error("Failed to send SNS notification: %s", str(e))


def handle_record_error(record, error):
    """Handle and log errors for a single record."""
    s3_event = record.get('s3', {})
    source_key = unquote_plus(s3_event.get('object', {}).get('key', 'unknown'))

    logger.error("Error processing %s: %s", source_key, str(error), exc_info=True)

    # Attempt to send error notification
    if SNS_TOPIC_ARN:
        try:
            sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Subject=f"❌ Image Processing Error: {os.path.basename(source_key)}"[:100],
                Message=json.dumps({
                    'error': str(error),
                    'source_key': source_key,
                    'timestamp': datetime.utcnow().isoformat() + 'Z'
                }),
                MessageAttributes={
                    'is_error': {
                        'DataType': 'String',
                        'StringValue': 'true'
                    }
                }
            )
        except Exception as notify_err:
            logger.error("Failed to send error notification: %s", str(notify_err))

    return {
        'status': 'error',
        'source_key': source_key,
        'error': str(error)
    }